		PillDosage.IsValid = (int x) => x > 0 && x <= castState.PillDosageLimit;
		BottleDosage.IsValid = (int x) => x >= 0 && x <= bottleAmountMax;
		if (PillNumber.Value > pillNumberMax)
		{
